New algorithm: Greedy insertion with regret heuristic and fallback to best feasible empty assign using time window proximity sorting.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx          int
		costIncrease float64
	}
	type orderInfo struct {
		orderIdx int
		score    float64
	}
	const EMPTY_THRESHOLD = 10

	allOrders := make([]orderInfo, len(oris))
	for i := range oris {
		dx := dess[i].X - oris[i].X
		dy := dess[i].Y - oris[i].Y
		timeWidth := dess[i].TimeEnd - oris[i].TimeStart
		if timeWidth <= 0 {
			timeWidth = 1
		}
		allOrders[i] = orderInfo{orderIdx: i, score: float64(dx*dx+dy*dy) / float64(timeWidth)}
	}

	sort.SliceStable(allOrders, func(i, j int) bool {
		return allOrders[i].score > allOrders[j].score
	})

	for _, oi := range allOrders {
		j := oi.orderIdx
		bestCandidate := candidate{idx: -1, costIncrease: 1e18}
		secondBestCandidate := candidate{idx: -1, costIncrease: 1e18}
		regretSum := 0.0
		feasibleCount := 0

		for ii := 0; ii < MAXASSIGNS; ii++ {
			if ii >= dispatch.AssignsLen && ii != dispatch.AssignsLen {
				continue
			}
			oldCost := dispatch.Assigns[ii].Cost
			if oldCost < 0 && ii < dispatch.AssignsLen {
				continue
			}
			addOk := false
			if ii < dispatch.AssignsLen {
				addOk = dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
			} else if ii == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[ii].StationCurrent = Station{X: 0, Y: 0, TimeStart: 0, TimeEnd: 86400, ReqCode: 0, Load: 0}
				dispatch.Assigns[ii].Cost = 0.0
				addOk = dispatch.Assigns[ii].AddShip(total_ship+j, oris[j], dess[j])
			}
			if addOk {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				increase := newCost - oldCost
				if increase < 0 {
					increase = 0
				}
				if increase < bestCandidate.costIncrease {
					secondBestCandidate = bestCandidate
					bestCandidate = candidate{idx: ii, costIncrease: increase}
				} else if increase < secondBestCandidate.costIncrease {
					secondBestCandidate = candidate{idx: ii, costIncrease: increase}
				}
				feasibleCount++
				dispatch.Assigns[ii].RemoveShip(total_ship + j)
				dispatch.Assigns[ii].GenRoute()
			} else if ii < dispatch.AssignsLen {
				dispatch.Assigns[ii].RemoveShip(total_ship + j)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		chosenIdx := -1
		if bestCandidate.idx != -1 && feasibleCount > 1 {
			if secondBestCandidate.idx != -1 {
				regretSum = secondBestCandidate.costIncrease - bestCandidate.costIncrease
			} else {
				regretSum = bestCandidate.costIncrease
			}
			if regretSum > 50 || feasibleCount <= 2 {
				chosenIdx = bestCandidate.idx
			} else {
				tempCandidates := []candidate{}
				for ii := 0; ii < MAXASSIGNS; ii++ {
					if ii >= dispatch.AssignsLen && ii != dispatch.AssignsLen {
						continue
					}
					oldCost := dispatch.Assigns[ii].Cost
