				dispatch.Assigns[idx].Cost = 0.0
				if dispatch.Assigns[idx].AddShip(total_ship+j, oris[j], dess[j]) {
					dispatch.Assigns[idx].GenRoute()
					if dispatch.Assigns[idx].Cost >= 0 {
